// GetOrder retrieves an order by ID.
func (s *UserOrderService) GetOrder(id string) (*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	order, ok := s.orders[id]
	if !ok {
		return nil, fmt.Errorf("order %s not found", id)
	}
	return order, nil
}

// ListOrdersByUser returns all orders belonging to a specific user.
func (s *UserOrderService) ListOrdersByUser(userID string) ([]*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	_, ok := s.users[userID]
	if !ok {
		return nil, fmt.Errorf("user %s not found", userID)
	}

	var result []*types.Order
	for _, order := range s.orders {
		if order.UserID == userID {
			result = append(result, order)
		}
	}
	return result, nil
}

// CancelOrder cancels an order. Only the order owner or an admin can cancel.
// Sends a cancellation notification.
func (s *UserOrderService) CancelOrder(orderID, cancelledByUserID string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[orderID]
	if !ok {
		return fmt.Errorf("order %s not found", orderID)
	}

	if order.Status == "cancelled" {
		return errors.New("order is already cancelled")
	}

	// Inline permission check — coupled to user store and admin roles
	cancellingUser, ok := s.users[cancelledByUserID]
	if !ok {
		return fmt.Errorf("user %s not found", cancelledByUserID)
	}

	isAdmin := false
	for _, role := range s.adminRoles {
		if cancellingUser.Role == role {
			isAdmin = true
			break
		}
	}

	if !isAdmin && order.UserID != cancelledByUserID {
		return errors.New("permission denied: only order owner or admin can cancel")
	}

	order.Status = "cancelled"

	// Look up the order owner to send notification — more coupling
	orderOwner, ownerExists := s.users[order.UserID]
	if ownerExists {
		subject := fmt.Sprintf("Order %s cancelled", orderID)
		body := fmt.Sprintf("Hi %s,\n\nYour order %s has been cancelled.\n\nIf you did not request this, please contact support.\n\nBest regards,\nThe Team", orderOwner.Name, orderID)
		notification := types.Notification{
			To:      orderOwner.Email,
			Subject: subject,
			Body:    body,
		}
		s.notifications = append(s.notifications, notification)
	}

	return nil
}

// CalculateTotal computes the total for a list of order items.
func (s *UserOrderService) CalculateTotal(items []types.OrderItem) float64 {
	var total float64
	for _, item := range items {
		total += item.Price * float64(item.Quantity)
	}
	return total
}

// GetNotifications returns all notifications that have been sent.
func (s *UserOrderService) GetNotifications() []types.Notification {
	s.mu.RLock()
	defer s.mu.RUnlock()

	result := make([]types.Notification, len(s.notifications))
	copy(result, s.notifications)
	return result
}

// ValidateEmail checks whether an email address is valid. Exported for external use.
func (s *UserOrderService) ValidateEmail(email string) error {
	if email == "" {
		return errors.New("email is required")
	}
	if !strings.Contains(email, "@") {
		return errors.New("email must contain @")
	}
	parts := strings.Split(email, "@")
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		return errors.New("email format is invalid")
	}
	if !strings.Contains(parts[1], ".") {
		return errors.New("email domain must contain a dot")
	}
	if s.emailDomain != "" && parts[1] != s.emailDomain {
		return fmt.Errorf("email must be from domain %s", s.emailDomain)
	}
	return nil
}

// ValidateOrder checks whether an order's items are valid. Exported for external use.
func (s *UserOrderService) ValidateOrder(items []types.OrderItem) error {
	if len(items) == 0 {
		return errors.New("order must have at least one item")
	}
	if len(items) > s.maxItems {
		return fmt.Errorf("order cannot exceed %d items", s.maxItems)
	}
	for i, item := range items {
		if item.ProductID == "" {
			return fmt.Errorf("item %d: product ID is required", i)
		}
		if item.Price < 0 {
			return fmt.Errorf("item %d: price cannot be negative", i)
		}
		if item.Quantity <= 0 {
			return fmt.Errorf("item %d: quantity must be positive", i)
		}
	}
	return nil
}

